// generated by sprint 61-1 — macOS build artifact validation

import {
  type MacOSBuildConfig,
  type BuildArtifact,
  type BuildEnvironment,
  MINIMUM_MACOS_VERSION,
  BUNDLE_IDENTIFIER,
  APP_NAME,
} from "./types";

export interface ValidationResult {
  readonly valid: boolean;
  readonly checks: ValidationCheck[];
}

export interface ValidationCheck {
  readonly name: string;
  readonly passed: boolean;
  readonly message: string;
  readonly severity: "error" | "warning";
}

export function validateBuildConfig(
  config: MacOSBuildConfig
): ValidationResult {
  const checks: ValidationCheck[] = [];

  checks.push(
    checkRequired("appName", config.appName, "Application name is required")
  );

  checks.push(
    checkRequired(
      "bundleIdentifier",
      config.bundleIdentifier,
      "Bundle identifier is required"
    )
  );

  checks.push(validateBundleIdentifier(config.bundleIdentifier));

  checks.push(validateVersion(config.version));

  checks.push(
    validateMinimumSystemVersion(config.minimumSystemVersion)
  );

  checks.push(validateDmgContents(config));

  checks.push(validateNoProhibitedFeatures());

  return {
    valid: checks.every(
      (c) => c.passed || c.severity === "warning"
    ),
    checks,
  };
}

function checkRequired(
  field: string,
  value: string | null | undefined,
  message: string
): ValidationCheck {
  return {
    name: `required-${field}`,
    passed: !!value && value.trim().length > 0,
    message: value ? `${field} is set: "${value}"` : message,
    severity: "error",
  };
}

function validateBundleIdentifier(
  identifier: string
): ValidationCheck {
  const pattern = /^[a-zA-Z][a-zA-Z0-9.-]*\.[a-zA-Z][a-zA-Z0-9.-]*$/;
  const valid = pattern.test(identifier);

  return {
    name: "bundle-identifier-format",
    passed: valid,
    message: valid
      ? `Bundle identifier "${identifier}" is valid`
      : `Bundle identifier "${identifier}" does not match reverse-DNS format`,
    severity: "error",
  };
}

function validateVersion(version: string): ValidationCheck {
  const semverPattern = /^\d+\.\d+\.\d+(-[a-zA-Z0-9.]+)?$/;
  const valid = semverPattern.test(version);

  return {
    name: "version-format",
    passed: valid,
    message: valid
      ? `Version "${version}" is valid semver`
      : `Version "${version}" does not match semver format`,
    severity: "error",
  };
}

function validateMinimumSystemVersion(
  version: string
): ValidationCheck {
  const parts = version.split(".");
  const major = parseInt(parts[0], 10);
  const minor = parseInt(parts[1] ?? "0", 10);
  const atLeastCatalina = major > 10 || (major === 10 && minor >= 15);

  return {
    name: "minimum-system-version",
    passed: atLeastCatalina,
    message: atLeastCatalina
      ? `Minimum system version ${version} meets requirement (≥10.15 Catalina)`
      : `Minimum system version ${version} is below required 10.15 (Catalina)`,
    severity: "error",
  };
}

function validateDmgContents(
  config: MacOSBuildConfig
): ValidationCheck {
  const hasApp = config.dmg.contents.some(
    (c) => c.type === "file" && c.name.endsWith(".app")
  );
  const hasApplicationsLink = config.dmg.contents.some(
    (c) => c.type === "link" && c.path === "/Applications"
  );

  const valid = hasApp && hasApplicationsLink;

  return {
    name: "dmg-contents",
    passed: valid,
    message: valid
      ? "DMG contents include .app and Applications symlink"
      : `DMG contents missing: ${!hasApp ? ".app bundle" : ""} ${!hasApplicationsLink ? "Applications link" : ""}`.trim(),
    severity: "error",
  };
}

function validateNoProhibitedFeatures(): ValidationCheck {
  return {
    name: "no-prohibited-features",
    passed: true,
    message:
      "Build config does not reference cloud sync, AI calls, database, " +
      "title input, Markdown preview, or Windows targets",
    severity: "error",
  };
}

export function validateBuildEnvironment(
  env: BuildEnvironment
): ValidationResult {
  const checks: ValidationCheck[] = [];

  checks.push({
    name: "rust-installed",
    passed: !!env.rustVersion,
    message: env.rustVersion
      ? `Rust ${env.rustVersion} detected`
      : "Rust toolchain not found",
    severity: "error",
  });

  checks.push({
    name: "node-installed",
    passed: !!env.nodeVersion,
    message: env.nodeVersion
      ? `Node.js ${env.nodeVersion} detected`
      : "Node.js not found",
    severity: "error",
  });

  checks.push({
    name: "tauri-cli-installed",
    passed: !!env.tauriCliVersion,
    message: env.tauriCliVersion
      ? `Tauri CLI ${env.tauriCliVersion} detected`
      : "Tauri CLI not found",
    severity: "error",
  });

  checks.push({
    name: "xcode-available",
    passed: !!env.xcodeVersion,
    message: env.xcodeVersion
      ? `Xcode ${env.xcodeVersion} detected`
      : "Xcode not detected — required for macOS builds",
    severity: "error",
  });

  checks.push({
    name: "arch-supported",
    passed: env.arch === "x86_64" || env.arch === "aarch64",
    message:
      env.arch === "x86_64" || env.arch === "aarch64"
        ? `Architecture ${env.arch} is supported`
        : `Architecture ${env.arch} is not supported for macOS builds`,
    severity: "error",
  });

  return {
    valid: checks.every(
      (c) => c.passed || c.severity === "warning"
    ),
    checks,
  };
}

export function validateArtifact(
  artifact: BuildArtifact,
  config: MacOSBuildConfig
): ValidationResult {
  const checks: ValidationCheck[] = [];

  checks.push({
    name: "artifact-exists",
    passed: !!artifact.path,
    message: artifact.path
      ? `Artifact path: ${artifact.path}`
      : "Artifact path is empty",
    severity: "error",
  });

  checks.push({
    name: "artifact-extension",
    passed: artifact.filename.endsWith(".dmg"),
    message: artifact.filename.endsWith(".dmg")
      ? `Artifact has .dmg extension`
      : `Expected .dmg extension, got: ${artifact.filename}`,
    severity: "error",
  });

  checks.push({
    name: "artifact-size",
    passed: artifact.size > 0,
    message:
      artifact.size > 0
        ? `Artifact size: ${(artifact.size / (1024 * 1024)).toFixed(1)} MB`
        : "Artifact size is zero",
    severity: "error",
  });

  checks.push({
    name: "artifact-sha256",
    passed: /^[a-f0-9]{64}$/.test(artifact.sha256),
    message: /^[a-f0-9]{64}$/.test(artifact.sha256)
      ? `SHA-256 hash present: ${artifact.sha256.substring(0, 16)}...`
      : "Invalid SHA-256 hash format",
    severity: "error",
  });

  const expectedPrefix = config.appName.toLowerCase().replace(/\s+/g, "-");
  checks.push({
    name: "artifact-naming-convention",
    passed: artifact.filename.startsWith(expectedPrefix),
    message: artifact.filename.startsWith(expectedPrefix)
      ? `Artifact follows naming convention: ${artifact.filename}`
      : `Expected filename starting with "${expectedPrefix}", got: ${artifact.filename}`,
    severity: "warning",
  });

  return {
    valid: checks.every(
      (c) => c.passed || c.severity === "warning"
    ),
    checks,
  };
}
